// Naming Candidates Generation
// Generates a set of brand name candidates with rationale and style metadata.
// In production, this node would be replaced with an LLM call or creative naming API.
const { projectId, stageKey, executionId, subStage } = $input.first().json.body;

const candidates = [
  {
    name: "Nexus",
    rationale: "Conveys connection and centrality — a hub where ideas and workflows converge. Short, punchy, and tech-forward.",
    domainHint: "nexus.io likely taken; nexushq.com or getnexus.dev may be available",
    styleTags: ["tech", "modern", "concise", "connectivity"]
  },
  {
    name: "Aether",
    rationale: "Evokes the invisible medium that powers everything — fitting for an automation layer that works behind the scenes.",
    domainHint: "aether.dev or useaether.com likely available",
    styleTags: ["ethereal", "premium", "abstract", "infrastructure"]
  },
  {
    name: "Catalyst",
    rationale: "Directly communicates acceleration and transformation. Strong B2B signal — implies enabling change without being consumed by it.",
    domainHint: "catalyst.app or catalystops.com worth checking",
    styleTags: ["action", "B2B", "transformation", "energy"]
  },
  {
    name: "Meridian",
    rationale: "Suggests a guiding line or peak — a reference point for navigation. Feels established and trustworthy.",
    domainHint: "meridian.co or runmeridian.com may be available",
    styleTags: ["premium", "navigation", "trust", "established"]
  },
  {
    name: "Loom",
    rationale: "Weaving together threads of work into a cohesive fabric. Short, memorable, and carries connotations of craft and precision.",
    domainHint: "loom.com taken; tryloom.dev or loomflow.io alternatives",
    styleTags: ["craft", "concise", "metaphorical", "creative"]
  },
  {
    name: "Stratum",
    rationale: "A foundational layer — positions the product as infrastructure that everything else builds upon. Scientific and solid.",
    domainHint: "stratum.dev or stratumhq.com worth checking",
    styleTags: ["infrastructure", "scientific", "foundational", "enterprise"]
  }
];

const methodology = "Candidates generated via semantic expansion from core product attributes (automation, orchestration, integration). Filtered for memorability (≤3 syllables), domain plausibility, and trademark clearance potential. Style tags derived from brand archetype mapping.";

return {
  json: {
    projectId,
    stageKey,
    executionId,
    subStage: subStage || 'naming_candidates',
    namingResult: {
      candidates,
      methodology,
      generatedAt: new Date().toISOString()
    }
  }
};
